// Generate a LARGE sample product-import .xlsx (2000 rows) for testing the importer
// at volume + every validation. Run from the repo root:
//   node apps/web/test/fixtures/make-sample-import-2000.mjs
// (xlsx resolves from apps/web/node_modules; output → docs/samples/.)
import { mkdirSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { cwd } from 'node:process';

import * as XLSX from 'xlsx';

const TOTAL = 2000; // == MAX_IMPORT_ROWS (tests the cap exactly)

const HEADER = [
  'Nama Produk*',
  'Kategori',
  'Deskripsi',
  'Grup Varian',
  'Nama Varian',
  'SKU',
  'Barcode',
  'Harga*',
  'Modal',
  'Stok',
];

const LONG =
  'Deskripsi contoh yang sengaja dibuat panjang untuk menguji truncate + tooltip pada kolom.';
const CATEGORIES = ['Apparel', 'Sepatu', 'Aksesoris', 'Tas', 'Elektronik', 'Dapur'];

// [productName, category, description, variantGroup, variantName, sku, barcode, price, cost, stock]
// Deliberate ERROR rows — one (or a pair) per validation the importer enforces.
const ERROR_ROWS = [
  ['', 'Apparel', '', '', 'Varian A', 'ERR-NOPROD', '', 10000, 5000, 1], // Nama Produk kosong
  ['Produk Tanpa Varian', 'Apparel', '', '', '', 'ERR-NOVAR', '', 10000, 5000, 1], // Nama Varian kosong
  ['Produk Tanpa Harga', 'Apparel', '', '', 'Default', 'ERR-NOPRICE', '', '', 5000, 1], // Harga kosong
  ['Harga Bukan Angka', 'Apparel', '', '', 'Default', 'ERR-PRICESTR', '', 'seratus ribu', 5000, 1],
  ['Harga Negatif', 'Apparel', '', '', 'Default', 'ERR-PRICENEG', '', -5000, 3000, 1],
  ['Modal Bukan Angka', 'Apparel', '', '', 'Default', 'ERR-COSTSTR', '', 10000, 'abc', 1],
  ['Stok Bukan Angka', 'Apparel', '', '', 'Default', 'ERR-STOCKSTR', '', 10000, 5000, 'banyak'],
  ['Stok Desimal', 'Apparel', '', '', 'Default', 'ERR-STOCKDEC', '', 10000, 5000, 1.5],
  ['Stok Negatif', 'Apparel', '', '', 'Default', 'ERR-STOCKNEG', '', 10000, 5000, -2],
  ['N'.repeat(220), 'Apparel', '', '', 'Default', 'ERR-LONGNAME', '', 10000, 5000, 1], // nama > 200
  ['SKU Kepanjangan', 'Apparel', '', '', 'Default', 'X'.repeat(70), '', 10000, 5000, 1], // SKU > 64
  [
    'Barcode Kepanjangan',
    'Apparel',
    '',
    '',
    'Default',
    'ERR-LONGBC',
    'B'.repeat(70),
    10000,
    5000,
    1,
  ],
  // Duplicate explicit SKU (both flagged):
  ['Duplikat Satu', 'Tas', '', '', 'Default', 'DUP-SKU', '', 10000, 5000, 1],
  ['Duplikat Dua', 'Tas', '', '', 'Default', 'DUP-SKU', '', 12000, 6000, 2],
  // Duplicate GENERATED SKU — blank SKU + identical product/variant name (both flagged):
  ['Barang Kembar', 'Aksesoris', '', '', 'Default', '', '', 15000, 7000, 3],
  ['Barang Kembar', 'Aksesoris', '', '', 'Default', '', '', 15000, 7000, 3],
];

const rows = [...ERROR_ROWS];

// Fill the rest with valid rows: standalone, grouped subvariants, and blank-SKU (auto-gen).
for (let i = 1; rows.length < TOTAL; i += 1) {
  const name = `Produk ${String(i).padStart(4, '0')}`;
  const category = CATEGORIES[i % CATEGORIES.length];
  const description = i % 3 === 0 ? LONG : '';
  const price = 10000 + (i % 90) * 1000;
  const cost = Math.round(price * 0.65);
  const stock = i % 120;

  if (i % 6 === 0) {
    // Grouped product: two subvariants sharing a Grup Varian.
    rows.push([name, category, description, 'Ukuran', 'S', `P${i}-S`, '', price, cost, stock]);
    if (rows.length < TOTAL) {
      rows.push([
        name,
        category,
        description,
        'Ukuran',
        'M',
        `P${i}-M`,
        '',
        price,
        cost,
        stock + 1,
      ]);
    }
  } else if (i % 5 === 0) {
    // Blank SKU → auto-generated by the importer ("auto" badge).
    rows.push([name, category, description, '', 'Default', '', '', price, cost, stock]);
  } else {
    rows.push([name, category, description, '', 'Default', `P${i}-01`, '', price, cost, stock]);
  }
}

const data = rows.slice(0, TOTAL); // exactly 2000 data rows

const sheet = XLSX.utils.aoa_to_sheet([HEADER, ...data]);
const workbook = XLSX.utils.book_new();
XLSX.utils.book_append_sheet(workbook, sheet, 'Produk');

const outDir = join(cwd(), 'docs', 'samples');
mkdirSync(outDir, { recursive: true });
const outPath = join(outDir, 'produk-2000-import.xlsx');
writeFileSync(outPath, XLSX.write(workbook, { type: 'buffer', bookType: 'xlsx' }));

console.log(
  `Wrote ${outPath} (${data.length} data rows, ${ERROR_ROWS.length} of them deliberate errors)`,
);
